const express = require('express');
const { Client } = require('@elastic/elasticsearch');
const bodyParser = require('body-parser');

const app = express();
app.use(bodyParser.json({ limit: '10mb' }));

const esClient = new Client({
  node: process.env.ELASTICSEARCH_URL || 'http://localhost:9200',
  auth: {
    username: process.env.ES_USERNAME || 'elastic',
    password: process.env.ES_PASSWORD || 'changeme'
  }
});

function buildBaseQuery(searchParams) {
  const { query, fields, filters, fuzzy, boost } = searchParams;
  
  let baseQuery = { bool: { must: [], filter: [], should: [] } };

  if (query) {
    if (fields && fields.length > 0) {
      baseQuery.bool.must.push({
        multi_match: {
          query: query,
          fields: fields,
          fuzziness: fuzzy ? 'AUTO' : undefined,
          boost: boost || 1
        }
      });
    } else {
      baseQuery.bool.must.push({
        query_string: {
          query: query,
          fuzziness: fuzzy ? 'AUTO' : undefined
        }
      });
    }
  }

  if (filters) {
    if (filters.term) {
      Object.entries(filters.term).forEach(([field, value]) => {
        baseQuery.bool.filter.push({ term: { [field]: value } });
      });
    }
    
    if (filters.range) {
      Object.entries(filters.range).forEach(([field, rangeParams]) => {
        baseQuery.bool.filter.push({ range: { [field]: rangeParams } });
      });
    }
    
    if (filters.exists) {
      filters.exists.forEach(field => {
        baseQuery.bool.filter.push({ exists: { field } });
      });
    }
    
    if (filters.terms) {
      Object.entries(filters.terms).forEach(([field, values]) => {
        baseQuery.bool.filter.push({ terms: { [field]: values } });
      });
    }
    
    if (filters.wildcard) {
      Object.entries(filters.wildcard).forEach(([field, value]) => {
        baseQuery.bool.filter.push({ wildcard: { [field]: value } });
      });
    }
    
    if (filters.regexp) {
      Object.entries(filters.regexp).forEach(([field, value]) => {
        baseQuery.bool.filter.push({ regexp: { [field]: value } });
      });
    }
  }

  return baseQuery;
}

function buildScriptScoreQuery(baseQuery, scriptConfig) {
  const { source, params, lang } = scriptConfig;
  
  return {
    script_score: {
      query: baseQuery,
      script: {
        source: source,
        params: params || {},
        lang: lang || 'painless'
      },
      min_score: scriptConfig.min_score,
      boost: scriptConfig.boost
    }
  };
}

function buildFunctionScoreQuery(baseQuery, functionConfig) {
  const { functions, score_mode, boost_mode, max_boost, min_score } = functionConfig;
  
  const functionScoreFunctions = functions.map(func => {
    const scoreFunction = {};
    
    if (func.filter) {
      scoreFunction.filter = func.filter;
    }
    
    if (func.weight) {
      scoreFunction.weight = func.weight;
    }
    
    if (func.script_score) {
      scoreFunction.script_score = {
        script: {
          source: func.script_score.source,
          params: func.script_score.params || {},
          lang: func.script_score.lang || 'painless'
        }
      };
    }
    
    if (func.field_value_factor) {
      scoreFunction.field_value_factor = func.field_value_factor;
    }
    
    if (func.decay) {
      const decayType = func.decay.type || 'gauss';
      scoreFunction[decayType] = {
        [func.decay.field]: {
          origin: func.decay.origin,
          scale: func.decay.scale,
          offset: func.decay.offset,
          decay: func.decay.decay
        }
      };
    }
    
    if (func.random_score) {
      scoreFunction.random_score = func.random_score;
    }
    
    return scoreFunction;
  });
  
  return {
    function_score: {
      query: baseQuery,
      functions: functionScoreFunctions,
      score_mode: score_mode || 'multiply',
      boost_mode: boost_mode || 'multiply',
      max_boost: max_boost,
      min_score: min_score
    }
  };
}

function buildAggregations(aggConfig) {
  if (!aggConfig) return undefined;
  
  const aggregations = {};
  
  Object.entries(aggConfig).forEach(([aggName, aggDef]) => {
    if (aggDef.terms) {
      aggregations[aggName] = {
        terms: {
          field: aggDef.terms.field,
          size: aggDef.terms.size || 10,
          order: aggDef.terms.order
        }
      };
    }
    
    if (aggDef.date_histogram) {
      aggregations[aggName] = {
        date_histogram: aggDef.date_histogram
      };
    }
    
    if (aggDef.range) {
      aggregations[aggName] = {
        range: aggDef.range
      };
    }
    
    if (aggDef.stats) {
      aggregations[aggName] = {
        stats: { field: aggDef.stats.field }
      };
    }
    
    if (aggDef.nested) {
      aggregations[aggName] = {
        nested: { path: aggDef.nested.path },
        aggs: buildAggregations(aggDef.nested.aggs)
      };
    }
  });
  
  return aggregations;
}

app.post('/api/search', async (req, res) => {
  try {
    const {
      index,
      searchParams,
      scriptScore,
      functionScore,
      aggregations,
      sort,
      from,
      size,
      source,
      highlight
    } = req.body;

    if (!index) {
      return res.status(400).json({ error: 'Index name is required' });
    }

    const baseQuery = buildBaseQuery(searchParams || {});
    
    let finalQuery;
    if (scriptScore) {
      finalQuery = buildScriptScoreQuery(baseQuery, scriptScore);
    } else if (functionScore) {
      finalQuery = buildFunctionScoreQuery(baseQuery, functionScore);
    } else {
      finalQuery = baseQuery;
    }

    const searchBody = {
      query: finalQuery,
      from: from || 0,
      size: size || 10
    };

    if (aggregations) {
      searchBody.aggs = buildAggregations(aggregations);
    }

    if (sort) {
      searchBody.sort = sort;
    }

    if (source !== undefined) {
      searchBody._source = source;
    }

    if (highlight) {
      searchBody.highlight = highlight;
    }

    const result = await esClient.search({
      index: index,
      body: searchBody
    });

    res.json({
      total: result.hits.total,
      hits: result.hits.hits,
      aggregations: result.aggregations,
      took: result.took
    });

  } catch (error) {
    console.error('Search error:', error);
    res.status(500).json({
      error: 'Search failed',
      message: error.message,
      details: error.meta?.body?.error
    });
  }
});

